"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["230353"],{727908(e){e.exports=JSON.parse('{"tag":{"label":"spawning","permalink":"/dst-api-webdocs/docs/tags/spawning","allTagsPath":"/dst-api-webdocs/docs/tags","count":35,"items":[{"id":"game-scripts/components/beargerspawner","title":"Beargerspawner","description":"Manages the seasonal spawning of the Bearger boss during autumn with warning systems and player targeting.","permalink":"/dst-api-webdocs/docs/game-scripts/components/beargerspawner"},{"id":"game-scripts/prefabs/beefaloherd","title":"Beefaloherd","description":"Manages beefalo herd behavior, mating seasons, and baby beefalo spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefaloherd"},{"id":"game-scripts/prefabs/beehive","title":"Beehive","description":"Defines the Beehive prefab entity that spawns bees, handles combat interactions, and drops loot when destroyed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beehive"},{"id":"game-scripts/components/birdspawner","title":"Birdspawner","description":"Manages bird spawning, tracking, and lunar hail event mechanics for the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/birdspawner"},{"id":"game-scripts/map/bunches","title":"Bunches","description":"Defines static spawning rules for grouped environmental props (bunches) such as seastacks, saltstacks, and rubbles across specific tile types.","permalink":"/dst-api-webdocs/docs/game-scripts/map/bunches"},{"id":"game-scripts/components/butterflyspawner","title":"Butterflyspawner","description":"Manages butterfly spawning and tracking on the master server based on player presence and world state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/butterflyspawner"},{"id":"game-scripts/prefabs/catcoonden","title":"Catcoonden","description":"Manages the lifecycle, inventory, and catcoon spawning behavior of the Catcoon Den structure in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/catcoonden"},{"id":"game-scripts/prefabs/cavelight","title":"Cavelight","description":"Manages dynamic lighting and spawning behavior for cave exit light sources, adjusting brightness, color, and presence based on world and cave phase states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cavelight"},{"id":"game-scripts/prefabs/cookiecutter_spawner","title":"Cookiecutter Spawner","description":"Spawns and manages Cookiecutter minions underwater, regenerating them over time based on tunable parameters and world settings.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cookiecutter_spawner"},{"id":"game-scripts/components/deciduoustreeupdater","title":"Deciduoustreeupdater","description":"Manages the transformation of a deciduous tree into a hostile monster state, controlling drake spawning, root attacks, and state transitions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/deciduoustreeupdater"},{"id":"game-scripts/components/deerclopsspawner","title":"Deerclopsspawner","description":"Manages Deerclops boss spawning, timing, and attack cycles on the server.","permalink":"/dst-api-webdocs/docs/game-scripts/components/deerclopsspawner"},{"id":"game-scripts/brains/dragonflybrain","title":"Dragonflybrain","description":"Manages AI behavior for the Dragonfly boss, including fight reset logic, Lavae spawning, chase/combat, and home patrolling.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/dragonflybrain"},{"id":"game-scripts/brains/eyeofterrorbrain","title":"Eyeofterrorbrain","description":"Controls the AI behavior of the Eye of Terror boss, coordinating special attacks, leashing, facing, and spawning mini-eyes via behavior trees.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/eyeofterrorbrain"},{"id":"game-scripts/prefabs/fishschoolspawnblocker","title":"Fishschoolspawnblocker","description":"Removes itself automatically after a fixed lifetime to prevent permanent obstruction of fish school spawn points.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fishschoolspawnblocker"},{"id":"game-scripts/components/flotsamgenerator","title":"Flotsamgenerator","description":"Spawns and manages floating debris (flotsam) in ocean environments, including scheduled natural spawns and guaranteed items like message bottles.","permalink":"/dst-api-webdocs/docs/game-scripts/components/flotsamgenerator"},{"id":"game-scripts/components/forestresourcespawner","title":"Forestresourcespawner","description":"Manages periodic spawning of renewable forest resources such as flint, saplings, and berry bushes near spawn points when no players are nearby.","permalink":"/dst-api-webdocs/docs/game-scripts/components/forestresourcespawner"},{"id":"game-scripts/components/gingerbreadhunter","title":"Gingerbreadhunter","description":"Manages the spawning and progression of gingerbread-themed hunts during events, including generating crumb trails and spawning gingerbread pigs or houses.","permalink":"/dst-api-webdocs/docs/game-scripts/components/gingerbreadhunter"},{"id":"game-scripts/prefabs/glommer","title":"Glommer","description":"A flying lunar-aligned companion entity that follows the player, enters sleep cycles, periodically spawns fuel items, and adjusts sanity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/glommer"},{"id":"game-scripts/prefabs/hermithouse","title":"Hermithouse","description":"Manages the hermit crab\u2019s home structure, including construction progression, friend-based recipe unlocking, hermit crab spawning, and pearl-based decoration scoring.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermithouse"},{"id":"game-scripts/components/lureplantspawner","title":"Lureplantspawner","description":"Manages dynamic lure plant spawning based on player movement trails during Spring season.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lureplantspawner"},{"id":"game-scripts/map/rooms/forest/merms","title":"Merms","description":"Defines the MermTown room template for forest worlds, specifying tile type, visual color, and spawn rules for merm-related structures and entities.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/merms"},{"id":"game-scripts/prefabs/oceanvine","title":"Oceanvine","description":"Manages the behavior, harvesting, burning, and dynamic spawing of ocean vines in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanvine"},{"id":"game-scripts/prefabs/oceanvine_cocoon","title":"Oceanvine Cocoon","description":"A flying spider cocoon that slowly spawns water spiders to hunt for ocean fish; it can be ignited or frozen, and drops silk, twigs, or ash upon destruction.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanvine_cocoon"},{"id":"game-scripts/components/penguinspawner","title":"Penguinspawner","description":"Manages seasonal penguin colony spawning, tracking, and lifecycle for winter events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/penguinspawner"},{"id":"game-scripts/components/periodicspawner","title":"Periodicspawner","description":"Manages timed, density-controlled spawning of prefabs around an entity with configurable intervals and spatial constraints.","permalink":"/dst-api-webdocs/docs/game-scripts/components/periodicspawner"},{"id":"game-scripts/prefabs/pigtorch","title":"Pigtorch","description":"A structure that produces guards and burns fuel over time, extinguishing when its fuel runs out or during rain.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pigtorch"},{"id":"game-scripts/components/rampingspawner","title":"Rampingspawner","description":"Manages progressive spawning of entities in waves, ramping up spawn count over time based on wave progression.","permalink":"/dst-api-webdocs/docs/game-scripts/components/rampingspawner"},{"id":"game-scripts/components/shadowcreaturespawner","title":"Shadowcreaturespawner","description":"Manages the spawning, tracking, and population control of shadow creatures (e.g., Crawling Horrors, Ocean Horrors, Terrorbeaks) for players based on sanity levels and game mode.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowcreaturespawner"},{"id":"game-scripts/components/shadowthrall_mimics","title":"Shadowthrall Mimics","description":"Manages spawning of shadow mimic entities that copy existing items during Cavenight when Shadow Rifts are active.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shadowthrall_mimics"},{"id":"game-scripts/simutil","title":"Simutil","description":"A global utility module providing helper functions for entity searching, vision checks, spawning logic, and asset atlas management.","permalink":"/dst-api-webdocs/docs/game-scripts/simutil"},{"id":"game-scripts/components/squidspawner","title":"Squidspawner","description":"Manages squid spawning based on player locations, moon phase, time of day, and nearby ocean trawlers during nights and dusk.","permalink":"/dst-api-webdocs/docs/game-scripts/components/squidspawner"},{"id":"game-scripts/prefabs/tallbirdnest","title":"Tallbirdnest","description":"Manages the tallbird nesting behavior, egg spawning, and seasonal reproduction cycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tallbirdnest"},{"id":"game-scripts/map/terrain","title":"Terrain","description":"Defines terrain tile restrictions for spawning in-game objects and provides access to room definitions via a deprecated lookup mechanism.","permalink":"/dst-api-webdocs/docs/game-scripts/map/terrain"},{"id":"game-scripts/components/wintersurprisespawner","title":"Wintersurprisespawner","description":"Manages the spawning of winter surprise trees during winter seasons, based on world state and player positioning rules.","permalink":"/dst-api-webdocs/docs/game-scripts/components/wintersurprisespawner"},{"id":"game-scripts/prefabs/wx78_heartveinspawner","title":"Wx78 Heartveinspawner","description":"Server-side prefab that periodically spawns shadow_heart_vein entities around WX-78 players using the shadow heart skill mechanic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wx78_heartveinspawner"}],"unlisted":false}}')}}]);